#[derive(Serialize, Deserialize)]
pub struct AppEvent {
    pub event_id:   Uuid,
    pub event_type: String,   // "INSERT_ORDER", "UPDATE_INVENTORY", "DELETE_RECORD"
    pub payload:    Value,    // JSON payload < 1KB
